const raw = $input.all()[0]?.json ?? {};
let payload = raw.query ?? {};
let parseError = false;

if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    payload = {};
    parseError = true;
  }
}

if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
  payload = {};
  parseError = true;
}

function str(value) {
  return String(value ?? '').trim();
}

const trusted = {
  senderOpenId: str(raw.trustedSenderOpenId),
  messageId: str(raw.trustedMessageId),
  messageText: str(raw.trustedMessageText),
  chatId: str(raw.trustedChatId),
  sessionKey: str(raw.trustedSessionKey),
};

const confirmMatch = trusted.messageText.match(/^\s*(?:确认|confirm)\s+(okrupd_[A-Za-z0-9_-]+)\s*$/i);
let action = str(payload.action || payload.operation || payload.tool);
if (!action && confirmMatch) action = 'execute_okr_update';

const aliases = {
  update_okr: 'propose_okr_update',
  propose: 'propose_okr_update',
  propose_update: 'propose_okr_update',
  patch_okr: 'propose_okr_update',
  confirm_okr_update: 'execute_okr_update',
  execute: 'execute_okr_update',
  execute_update: 'execute_okr_update',
};
action = aliases[action] || action;

const supportedActions = ['propose_okr_update', 'execute_okr_update'];
const proposalId = str(payload.proposalId || payload.proposal_id || confirmMatch?.[1]);

return [{
  json: {
    ok: supportedActions.includes(action),
    action: supportedActions.includes(action) ? action : 'unknown_action',
    requestedAction: action || 'unknown',
    supportedActions,
    parseError,
    toolInput: payload,
    proposalId,
    trusted,
  },
}];

const request = $('Normalize').all()[0]?.json ?? {};
const payload = request.toolInput ?? {};

function str(value) {
  return String(value ?? '').trim();
}

function finish(ok, output, extra = {}, errorCode = 'PROPOSE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'propose_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

function hasOwn(obj, key) {
  return Object.prototype.hasOwnProperty.call(obj, key);
}

function findForbidden(value, path = '') {
  const forbidden = new Set([
    'delete',
    'weight',
    'order',
    'position',
    'alignment',
    'indicator',
    'indicators',
    'notes',
    'category_id',
    'progress',
    'owner',
    'mentioned_user_list',
  ]);
  if (!value || typeof value !== 'object') return '';
  for (const [key, nested] of Object.entries(value)) {
    const normalized = key.toLowerCase();
    if (forbidden.has(normalized)) return path ? path + '.' + key : key;
    const found = findForbidden(nested, path ? path + '.' + key : key);
    if (found) return found;
  }
  return '';
}

function contentBlock(text) {
  return {
    blocks: [
      {
        block_element_type: 'paragraph',
        paragraph: {
          elements: [
            {
              paragraph_element_type: 'textRun',
              text_run: { text },
            },
          ],
        },
      },
    ],
  };
}

function parseScore(value) {
  if (value === undefined || value === null || value === '') return { present: false };
  const raw = String(value).trim();
  const percent = raw.endsWith('%');
  const numeric = Number(percent ? raw.slice(0, -1) : raw);
  if (!Number.isFinite(numeric)) return { error: 'INVALID_SCORE' };
  const score = percent || numeric > 1 ? numeric / 100 : numeric;
  if (score < 0 || score > 1) return { error: 'SCORE_OUT_OF_RANGE' };
  return { present: true, value: Math.round(score * 10) / 10 };
}

function parseDeadline(value) {
  if (value === undefined || value === null || value === '') return { present: false };
  const raw = String(value).trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(raw)) return { error: 'DEADLINE_REQUIRES_YYYY_MM_DD' };
  const ms = Date.parse(raw + 'T23:59:59+08:00');
  if (!Number.isFinite(ms)) return { error: 'INVALID_DEADLINE' };
  return { present: true, value: String(ms), display: raw };
}

if (request.parseError) return finish(false, '修改 OKR 的参数不是有效 JSON。', {}, 'INVALID_TOOL_INPUT');
if (!request.trusted?.senderOpenId || !request.trusted?.messageId || !request.trusted?.sessionKey) {
  return finish(false, '缺少可信消息上下文，不能修改 OKR。', {}, 'MISSING_TRUSTED_CONTEXT');
}

const patchInput = payload.patch && typeof payload.patch === 'object' && !Array.isArray(payload.patch)
  ? payload.patch
  : payload;
const forbidden = findForbidden(patchInput);
if (forbidden) {
  return finish(false, '暂不支持修改字段：' + forbidden + '。', { forbiddenField: forbidden }, 'FORBIDDEN_OKR_FIELD');
}

const targetTypeRaw = str(payload.targetType || payload.entityType || payload.type);
const targetType = ['objective', 'o'].includes(targetTypeRaw.toLowerCase())
  ? 'objective'
  : (['key_result', 'keyResult', 'kr', 'key-result'].includes(targetTypeRaw) || targetTypeRaw.toLowerCase() === 'keyresult'
    ? 'key_result'
    : '');
const targetId = str(payload.targetId || payload.entityId || payload.objectiveId || payload.keyResultId);

if (!targetType) return finish(false, '缺少 targetType，目前只支持 objective 或 key_result。', {}, 'MISSING_TARGET_TYPE');
if (!targetId) return finish(false, '缺少 targetId/objectiveId/keyResultId。', {}, 'MISSING_TARGET_ID');
if (payload.targetUserId && str(payload.targetUserId) !== request.trusted.senderOpenId) {
  return finish(false, '第一版只允许修改你自己的 OKR。', {}, 'WRITE_SELF_ONLY');
}

const patchBody = {};
const patchSummary = [];
const contentValue = hasOwn(patchInput, 'contentText') ? patchInput.contentText
  : (hasOwn(patchInput, 'newContent') ? patchInput.newContent
    : (hasOwn(patchInput, 'content') ? patchInput.content : undefined));
if (contentValue !== undefined) {
  if (typeof contentValue !== 'string') return finish(false, 'content 只接受纯文本。', {}, 'CONTENT_MUST_BE_TEXT');
  const text = str(contentValue);
  if (!text) return finish(false, 'content 不能为空。', {}, 'EMPTY_CONTENT');
  if (text.length > 300) return finish(false, 'content 过长，第一版最多 300 字。', {}, 'CONTENT_TOO_LONG');
  patchBody.content = contentBlock(text);
  patchSummary.push('内容 -> ' + text);
}

const scoreValue = hasOwn(patchInput, 'score') ? patchInput.score : (hasOwn(patchInput, 'progress') ? patchInput.progress : undefined);
const score = parseScore(scoreValue);
if (score.error) return finish(false, '分数必须在 0-1 或 0%-100% 之间。', {}, score.error);
if (score.present) {
  patchBody.score = score.value;
  patchSummary.push('分数 -> ' + score.value + ' (' + Math.round(score.value * 100) + '%)');
}

const deadline = parseDeadline(hasOwn(patchInput, 'deadline') ? patchInput.deadline : patchInput.deadlineDate);
if (deadline.error) return finish(false, '截止日期必须使用明确日期 YYYY-MM-DD。', {}, deadline.error);
if (deadline.present) {
  patchBody.deadline = deadline.value;
  patchSummary.push('截止日期 -> ' + deadline.display);
}

if (Object.keys(patchBody).length === 0) {
  return finish(false, '没有可修改字段。第一版只支持 content、score、deadline。', {}, 'EMPTY_PATCH');
}

function okrEndpoint(targetType, targetId) {
  const resource = targetType === 'objective' ? 'objectives' : 'key_results';
  return 'https://open.feishu.cn/open-apis/okr/v2/' + resource + '/' + encodeURIComponent(targetId);
}

return finish(true, 'OKR 修改请求已通过基础校验。', {
  targetType,
  targetId,
  okrHttpMethod: 'GET',
  okrHttpUrl: okrEndpoint(targetType, targetId),
  patchBody,
  patchSummary,
  trusted: request.trusted,
});

const currentInput = $input.all()[0]?.json ?? {};
const request = $('Validate update proposal').all()[0]?.json ?? {};

function str(value) {
  return String(value ?? '').trim();
}

function finish(ok, output, extra = {}, errorCode = 'PROPOSE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'propose_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

function contentText(content) {
  const blocks = content?.blocks;
  if (!Array.isArray(blocks)) return '';
  const parts = [];
  for (const block of blocks) {
    const elements = block?.paragraph?.elements;
    if (!Array.isArray(elements)) continue;
    for (const element of elements) {
      const text = element?.text_run?.text;
      if (text) parts.push(String(text));
    }
  }
  return parts.join('');
}

function entityFrom(input, targetType) {
  if (targetType === 'objective') return input.objective ?? input.data?.objective;
  return input.key_result ?? input.keyResult ?? input.data?.key_result ?? input.data?.keyResult;
}

if (!request.ok) return finish(false, request.output || '修改请求未通过校验。', request, request.error?.code || 'PROPOSAL_VALIDATION_FAILED');
if (currentInput.error) {
  const detail = typeof currentInput.error === 'string' ? currentInput.error : (currentInput.error.message || JSON.stringify(currentInput.error));
  return finish(false, '读取当前 OKR 失败：' + detail, { targetType: request.targetType, targetId: request.targetId }, 'READ_TARGET_FAILED');
}
if (currentInput.code && currentInput.code !== 0) {
  return finish(false, '读取当前 OKR 失败：' + (currentInput.msg || JSON.stringify(currentInput)), { targetType: request.targetType, targetId: request.targetId }, 'READ_TARGET_API_ERROR');
}

const entity = entityFrom(currentInput, request.targetType);
if (!entity?.id) {
  return finish(false, '没有找到要修改的 OKR 项。', { targetType: request.targetType, targetId: request.targetId }, 'TARGET_NOT_FOUND');
}

const ownerOpenId = str(entity.owner?.user_id);
if (!ownerOpenId || ownerOpenId !== request.trusted.senderOpenId) {
  return finish(false, '第一版只允许修改你自己的 OKR。', { ownerOpenId, requesterOpenId: request.trusted.senderOpenId }, 'WRITE_TARGET_NOT_OWNED');
}

const beforeSnapshot = {
  targetType: request.targetType,
  targetId: entity.id,
  ownerOpenId,
  contentText: contentText(entity.content),
  score: entity.score ?? null,
  deadline: entity.deadline ?? '',
  updateTime: entity.update_time ?? '',
  objectiveId: entity.objective_id ?? '',
  cycleId: entity.cycle_id ?? '',
};

const now = Date.now();
const proposalId = 'okrupd_' + now.toString(36) + '_' + Math.random().toString(36).slice(2, 8);
const expiresAt = now + 10 * 60 * 1000;
const summary = [
  '待修改 ' + (request.targetType === 'objective' ? 'Objective' : 'Key Result') + '：' + entity.id,
  ...request.patchSummary,
].join('\n');

return finish(true, [
  '已生成 OKR 修改草案：' + proposalId,
  summary,
  '如确认执行，请在 10 分钟内回复：确认 ' + proposalId,
].join('\n'), {
  proposalId,
  requesterOpenId: request.trusted.senderOpenId,
  chatId: request.trusted.chatId,
  sessionKey: request.trusted.sessionKey,
  sourceMessageId: request.trusted.messageId,
  targetType: request.targetType,
  targetId: entity.id,
  patchBodyJson: JSON.stringify(request.patchBody),
  beforeSnapshotJson: JSON.stringify(beforeSnapshot),
  summaryText: summary,
  proposalStatus: 'pending',
  createdAtMs: now,
  expiresAtMs: expiresAt,
  confirmedMessageId: '',
  executedAtMs: 0,
  errorCode: '',
  resultJson: '',
  data: {
    proposalId,
    targetType: request.targetType,
    targetId: entity.id,
    patchBody: request.patchBody,
    beforeSnapshot,
    expiresAt,
  },
});

const input = $input.all()[0]?.json ?? {};
const builtNode = $('Build update proposal');
const built = builtNode.isExecuted ? builtNode.all()[0]?.json : undefined;
const source = built?.proposalId ? built : input;

function finish(ok, output, extra = {}, errorCode = 'PROPOSE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'propose_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

if (!source.ok) return finish(false, source.output || '生成 OKR 修改草案失败。', source, source.error?.code || 'PROPOSAL_FAILED');
if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish(false, '保存 OKR 修改草案失败：' + detail, source, 'SAVE_PROPOSAL_FAILED');
}

return finish(true, source.output, {
  status: 'pending',
  proposalId: source.proposalId,
  data: source.data,
});

const row = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};

function str(value) {
  return String(value ?? '').trim();
}

function finish(ok, output, extra = {}, errorCode = 'EXECUTE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'execute_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

const confirmMatch = str(request.trusted?.messageText).match(/^\s*(?:确认|confirm)\s+(okrupd_[A-Za-z0-9_-]+)\s*$/i);
if (!confirmMatch) return finish(false, '执行 OKR 修改前，请精确回复：确认 <proposalId>。', {}, 'CONFIRMATION_REQUIRED');
const proposalId = confirmMatch[1];
if (request.proposalId && request.proposalId !== proposalId) {
  return finish(false, '确认消息中的 proposalId 与工具参数不一致。', { proposalId }, 'PROPOSAL_ID_MISMATCH');
}
if (!row.proposalId) return finish(false, '没有找到该 OKR 修改草案，可能已过期或未创建。', { proposalId }, 'PROPOSAL_NOT_FOUND');
if (row.proposalId !== proposalId) return finish(false, '读取到的 proposal 与确认消息不一致。', { proposalId, rowProposalId: row.proposalId }, 'PROPOSAL_ID_MISMATCH');
if (row.proposalStatus !== 'pending') return finish(false, '该 OKR 修改草案状态不是 pending：' + row.proposalStatus, { proposalId, status: row.proposalStatus }, 'PROPOSAL_NOT_PENDING');
if (Number(row.expiresAtMs || 0) < Date.now()) return finish(false, '该 OKR 修改草案已过期，请重新发起修改。', { proposalId }, 'PROPOSAL_EXPIRED');
if (row.requesterOpenId !== request.trusted.senderOpenId) return finish(false, '只有发起人本人可以确认该 OKR 修改。', { proposalId }, 'CONFIRM_SENDER_MISMATCH');
if (row.chatId !== request.trusted.chatId) return finish(false, '确认消息不在原会话中。', { proposalId }, 'CONFIRM_CHAT_MISMATCH');
if (row.sessionKey !== request.trusted.sessionKey) return finish(false, '确认消息不在原上下文中。', { proposalId }, 'CONFIRM_SESSION_MISMATCH');
if (row.sourceMessageId === request.trusted.messageId) return finish(false, '不能用创建草案的同一条消息确认执行。', { proposalId }, 'SAME_MESSAGE_CONFIRM_FORBIDDEN');

function okrEndpoint(targetType, targetId) {
  const resource = targetType === 'objective' ? 'objectives' : 'key_results';
  return 'https://open.feishu.cn/open-apis/okr/v2/' + resource + '/' + encodeURIComponent(targetId);
}

let patchBody;
let beforeSnapshot;
try {
  patchBody = JSON.parse(row.patchBodyJson || '{}');
  beforeSnapshot = JSON.parse(row.beforeSnapshotJson || '{}');
} catch (error) {
  return finish(false, '草案数据损坏，请重新发起修改。', { proposalId }, 'PROPOSAL_DATA_INVALID');
}

return finish(true, 'OKR 修改草案已确认，准备执行。', {
  proposalId,
  targetType: row.targetType,
  targetId: row.targetId,
  okrHttpMethod: 'GET',
  okrHttpUrl: okrEndpoint(row.targetType, row.targetId),
  patchBody,
  beforeSnapshot,
  row,
  trusted: request.trusted,
});

const currentInput = $input.all()[0]?.json ?? {};
const request = $('Verify update proposal').all()[0]?.json ?? {};

function finish(ok, output, extra = {}, errorCode = 'EXECUTE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'execute_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

function contentText(content) {
  const blocks = content?.blocks;
  if (!Array.isArray(blocks)) return '';
  const parts = [];
  for (const block of blocks) {
    const elements = block?.paragraph?.elements;
    if (!Array.isArray(elements)) continue;
    for (const element of elements) {
      const text = element?.text_run?.text;
      if (text) parts.push(String(text));
    }
  }
  return parts.join('');
}

function entityFrom(input, targetType) {
  if (targetType === 'objective') return input.objective ?? input.data?.objective;
  return input.key_result ?? input.keyResult ?? input.data?.key_result ?? input.data?.keyResult;
}

function okrEndpoint(targetType, targetId) {
  const resource = targetType === 'objective' ? 'objectives' : 'key_results';
  return 'https://open.feishu.cn/open-apis/okr/v2/' + resource + '/' + encodeURIComponent(targetId);
}

if (!request.ok) return finish(false, request.output || '确认未通过。', request, request.error?.code || 'CONFIRMATION_FAILED');
if (currentInput.error) {
  const detail = typeof currentInput.error === 'string' ? currentInput.error : (currentInput.error.message || JSON.stringify(currentInput.error));
  return finish(false, '执行前重新读取 OKR 失败：' + detail, request, 'READ_TARGET_FAILED');
}
if (currentInput.code && currentInput.code !== 0) {
  return finish(false, '执行前重新读取 OKR 失败：' + (currentInput.msg || JSON.stringify(currentInput)), request, 'READ_TARGET_API_ERROR');
}

const entity = entityFrom(currentInput, request.targetType);
if (!entity?.id) return finish(false, '执行前没有找到目标 OKR 项。', request, 'TARGET_NOT_FOUND');
const before = request.beforeSnapshot || {};
const currentSnapshot = {
  contentText: contentText(entity.content),
  score: entity.score ?? null,
  deadline: entity.deadline ?? '',
  updateTime: entity.update_time ?? '',
};

const drift = [];
if (String(before.updateTime ?? '') && String(before.updateTime ?? '') !== String(currentSnapshot.updateTime ?? '')) drift.push('updateTime');
if (String(before.contentText ?? '') !== String(currentSnapshot.contentText ?? '')) drift.push('content');
if (String(before.score ?? '') !== String(currentSnapshot.score ?? '')) drift.push('score');
if (String(before.deadline ?? '') !== String(currentSnapshot.deadline ?? '')) drift.push('deadline');
if (drift.length) {
  return finish(false, 'OKR 已在草案生成后发生变化，请重新生成修改草案。', {
    ...request,
    drift,
    currentSnapshot,
  }, 'OKR_DRIFT_DETECTED');
}

return finish(true, 'OKR 未发生漂移，准备写入。', {
  ...request,
  currentSnapshot,
  okrHttpMethod: 'PATCH',
  okrHttpUrl: okrEndpoint(request.targetType, request.targetId),
});

const input = $input.all()[0]?.json ?? {};
const request = $('Check OKR drift').all()[0]?.json ?? {};

function finish(ok, output, extra = {}, errorCode = 'EXECUTE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'execute_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

if (!request.ok) return finish(false, request.output || '执行条件未通过。', request, request.error?.code || 'EXECUTION_GUARD_FAILED');
if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish(false, '写入 OKR 失败：' + detail, request, 'PATCH_OKR_FAILED');
}
if (input.code && input.code !== 0) {
  return finish(false, '写入 OKR 失败：' + (input.msg || JSON.stringify(input)), request, 'PATCH_OKR_API_ERROR');
}

const now = Date.now();
return finish(true, 'OKR 修改已执行。', {
  ...request,
  proposalStatus: 'executed',
  confirmedMessageId: request.trusted?.messageId || '',
  executedAtMs: now,
  errorCode: '',
  resultJson: JSON.stringify(input),
  data: {
    proposalId: request.proposalId,
    targetType: request.targetType,
    targetId: request.targetId,
    result: input,
  },
});

const input = $input.all()[0]?.json ?? {};
const patchNode = $('Format patch result');
const patch = patchNode.isExecuted ? patchNode.all()[0]?.json : undefined;
const source = patch?.proposalId ? patch : input;

function finish(ok, output, extra = {}, errorCode = 'EXECUTE_OKR_UPDATE_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'execute_okr_update',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

if (!source.ok) return finish(false, source.output || 'OKR 修改未执行。', source, source.error?.code || 'EXECUTE_OKR_UPDATE_FAILED');
if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish(false, 'OKR 已写入，但更新草案状态失败：' + detail, source, 'MARK_PROPOSAL_EXECUTED_FAILED');
}

return finish(true, 'OKR 修改已完成。', {
  status: 'executed',
  proposalId: source.proposalId,
  data: source.data,
});

const request = $('Normalize').all()[0]?.json ?? {};
return [{
  json: {
    ok: false,
    action: request.requestedAction || 'unknown_action',
    version: 'v1',
    error: {
      code: 'UNSUPPORTED_ACTION',
      message: 'okr_write_tools 不支持 action：' + (request.requestedAction || 'unknown'),
      retryable: false,
    },
    supportedActions: request.supportedActions || [],
    output: '不支持该 OKR 写入操作。',
  },
}];
